import { Component } from "react";

const styles = {
    fontWeight: 'bold',
}

class Descripcion extends Component {
    render() {
        const { children, importante } = this.props
        if (importante === false) {
            return(
                <p className='descripcion'>{ children }</p>
            )
        }
        else {
            return(
                <p className='descripcion' style={styles}>{ children }</p>
            )
        }

    }
}

export default Descripcion
